What does the following program print?

```cpp
#include <iostream>

void bump(int& x, int delta) {
    x = x + delta;
}

int main() {
    int a = 10;
    bump(a, 3);
    bump(a, -1);
    std::cout << a << '\n';
}
```

The function below is supposed to swap two integers in place, but after calling it `a` and `b` are unchanged. What is the bug?

```cpp
#include <iostream>

void mySwap(int a, int b) {
    int tmp = a;
    a = b;
    b = tmp;
}

int main() {
    int x = 1, y = 2;
    mySwap(x, y);
    std::cout << x << ' ' << y << '\n';
}
```

What does the following program print?

```cpp
#include <iostream>

void fill(int* out, int value) {
    *out = value;
}

int main() {
    int result = 99;
    fill(&result, 7);
    std::cout << result << '\n';
}
```
